(10, '2026-07-08 18:00:00', NULL, 'quest_material', 'Species DNA (Snake)', 'Genetic sample from serpent species, used in Trainer specialization.', 0, 0, 0, 'S', 'N', 'N', 'N', 'N', 'none', 'S', 9999, 'N', 'N', 'N', 'N', 'DNA di specie (Serpente)', 'DNA de especie (Cobra)', 'Campione genetico da serpenti per la specializzazione Allenatore.', 'Amostra genetica de serpentes para especializacao Treinador.'),
(11, '2026-07-08 18:00:00', NULL, 'quest_material', 'Ki\'s Training Seal', 'A token earned only from earth-aligned snakes during the Trainer trial.', 0, 0, 0, 'S', 'N', 'N', 'N', 'N', 'none', 'S', 9999, 'N', 'N', 'N', 'N', 'Sigillo di addestramento di Ki', 'Selo de treino de Ki', 'Gettone ottenuto solo da serpenti di terra durante la prova Allenatore.', 'Token obtido apenas de cobras de terra durante a prova Treinador.')
