(1, 1, 'nerd_shard_identify', 'Keen Eye', 'Occhio attento', 'Olho atento', '+5% element shard identify rate on wild inspect.', '+5% identificazione frammenti al ispezionare selvatici.', '+5% identificacao de fragmentos ao inspecionar.', 'field', 0, 0, '{\"type\":\"passive\",\"stat\":\"shard_identify\",\"percent\":5}', 1, 'S'),
(2, 1, 'nerd_accuracy_aura', 'Steady Focus', 'Mira stabile', 'Foco estavel', '+5% accuracy on team when you act first in a round.', '+5% precisione alla squadra quando agisci per primo nel turno.', '+5% precisao na equipa quando ages primeiro na ronda.', 'battle', 0, 0, '{\"type\":\"passive\",\"stat\":\"acc\",\"percent\":5,\"when\":\"acts_first_in_round\"}', 1, 'S'),
(3, 2, 'stud_move_speed', 'Long Stride', 'Passo lungo', 'Passo longo', '+5% move speed outside battle.', '+5% velocita di movimento fuori lotta.', '+5% velocidade de movimento fora de combate.', 'field', 0, 0, '{\"type\":\"passive\",\"stat\":\"move_speed\",\"percent\":5}', 1, 'S'),
(4, 2, 'stud_first_crit', 'Opening Blow', 'Colpo iniziale', 'Golpe inicial', '+5% crit on first animal attack each battle.', '+5% crit sul primo attacco animale per lotta.', '+5% crit no primeiro ataque animal por batalha.', 'battle', 0, 0, '{\"type\":\"passive\",\"stat\":\"cr\",\"percent\":5,\"when\":\"first_attack_per_battle\"}', 1, 'S'),
(5, 4, 'scientist_analyze', 'Analyze', 'Analizza', 'Analisar', 'Reveal enemy resistances and next AI tendency for 1 turn.', 'Rivela resistenze nemiche e la prossima mossa IA per 1 turno.', 'Revela resistencias inimigas e a proxima tendencia IA por 1 turno.', 'battle', 3, 0, '{\"type\":\"active\",\"effect\":\"analyze_enemy\"}', 25, 'S'),
(6, 4, 'scientist_sample', 'Sample', 'Campiona', 'Amostra', 'Sample wild remains for bestiary progress.', 'Campiona resti selvatici per progressi bestiario.', 'Amostra restos selvagens para progresso do bestiario.', 'field', 0, 300, '{\"type\":\"active\",\"effect\":\"sample_wild\"}', 25, 'S'),
(7, 5, 'trainer_command', 'Command', 'Comando', 'Comando', 'Next animal move +15% power or +1 priority (2-turn CD).', 'Prossima mossa animale +15% potenza o +1 priorita (CD 2 turni).', 'Proximo movimento animal +15% poder ou +1 prioridade (CD 2 turnos).', 'battle', 2, 0, '{\"type\":\"active\",\"effect\":\"command_boost\"}', 25, 'S'),
(8, 5, 'trainer_camp_train', 'Camp Training', 'Addestramento accampamento', 'Treino no acampamento', 'Small daily EXP drip to one animal at camp (daily cap).', 'Piccola EXP giornaliera a un animale in accampamento (limite giornaliero).', 'EXP diaria a um animal no acampamento (limite diario).', 'field', 0, 86400, '{\"type\":\"active\",\"effect\":\"camp_train\"}', 25, 'S')
