INSERT INTO `playanimaster_db`.`dialogues` (`id_dialog`, `id_conversation`, `order`, `flg_last`, `flg_options`, `dialog`, `dialog_it`, `dialog_pt`) VALUES
(4, 3, 1, 'S', 'N', 'Hello! Good to see you again.', 'Ciao! Che piacere rivederti.', 'Ola! Bom te ver outra vez.'),
(5, 4, 1, 'N', 'N', 'Hello! Welcome to Animaster.', 'Ciao! Benvenuto in Animaster.', 'Ola! Bem-vindo ao Animaster.'),
(6, 4, 2, 'S', 'S', 'You do not have any animals yet. Would you like to receive your first companion?', 'Non hai ancora nessun animale. Vuoi ricevere il tuo primo compagno?', 'Ainda nao tens nenhum animal. Queres receber o teu primeiro companheiro?'),
(11, 6, 1, 'N', 'N', 'Traveler, be careful out there. The wild animals in this zone have become aggressive and unpredictable.', 'Viaggiatore, fai attenzione la fuori. Gli animali selvaggi in questa zona sono diventati aggressivi e imprevedibili.', 'Viajante, tem cuidado la fora. Os animais selvagens nesta zona tornaram-se agressivos e imprevisiveis.'),
(12, 6, 2, 'N', 'N', 'If your team gets hurt, use Potions outside battle. Always keep a few with you before exploring.', 'Se la tua squadra si ferisce, usa le Pozioni fuori dalla lotta. Tienine sempre qualcuna prima di esplorare.', 'Se a tua equipa se magoar, usa Pocoes fora de combate. Mantem sempre algumas contigo antes de explorar.'),
(13, 6, 3, 'S', 'S', 'Here, take this Potion. Stay safe!', 'Ecco, prendi questa Pozione. Stai attento!', 'Toma, fica com esta Pocao. Cuida-te!'),
(14, 7, 1, 'S', 'N', 'Hello! Good to see you again.', 'Ciao! Che piacere rivederti.', 'Ola! Bom te ver outra vez.'),
(15, 8, 2, 'S', 'S', 'A strong trainer builds their team step by step. You still have room for another companion ??? want me to find one for you?', 'Un buon allenatore costruisce la squadra un passo alla volta. Hai ancora spazio per un altro compagno ??? vuoi che te ne trovi uno?', 'Um bom treinador forma a equipa passo a passo. Ainda tens espaco para outro companheiro ??? queres que te arranje um?'),
(16, 9, 1, 'S', 'S', 'Back again? Good. You are ready for a third partner on your journey. Shall I find one for you?', 'Di nuovo qui? Bene. Sei pronto per un terzo compagno di viaggio. Te ne cerco uno?', 'Outra vez? Otimo. Estas pronto para um terceiro parceiro de viagem. Arranjo-te um?'),
(17, 10, 1, 'N', 'N', 'Your field data is promising. With the materials you brought, we can register you as a Scientist.', 'I tuoi dati sul campo sono promettenti. Con i materiali che hai portato possiamo registrarti come Scienziato.', 'Os teus dados de campo sao promissores. Com os materiais que trouxeste podemos registar-te como Cientista.'),
(18, 10, 2, 'S', 'S', 'Are you ready to specialize as a Scientist? This choice is permanent.', 'Sei pronto a specializzarti come Scienziato? Questa scelta e permanente.', 'Estas pronto para te especializares como Cientista? Esta escolha e permanente.'),
(19, 11, 1, 'S', 'N', 'Keep training and come back (lvl8)', 'Continua ad allenarti e torna da me (lvl8)', 'Continua a treinar e volta aqui (lvl8)'),
(20, 8, 1, 'N', 'N', 'Hi there! My name is Tamer. I\'m here to help the Prof\'s animal friends continue to improve.', 'Ciao! Mi chiamo Tamer. Sono qui per aiutare gli amici del Prof a migliorare.', 'Ola! Sou o Tamer. Estou aqui para ajudar os novos amigos do Prof a melhorar.'),
(21, 12, 1, 'N', 'N', 'Hello there! How are the puppies?', 'Ciao! Come stanno i cuccioli?', 'Ola! Como estao os bebes?'),
(22, 12, 2, 'S', 'N', 'Ohh I can see they\'re growing well. Keep up the good work :)', 'Ahh vedo che stanno crescendo! Continua cosi :)', 'AHH tou a ver que estao a crescer bem! continua assim :)'),
(23, 13, 1, 'N', 'N', 'Hello there. I specialize in those who seek to master knowledge.', 'Hello there. I specialize in those who seek to master knowledge.', 'Hello there. I specialize in those who seek to master knowledge.'),
(24, 13, 1, 'N', 'N', 'You seem more of a... \"hands-on\" type of individual...', 'You seem more of a... \"hands-on\" type of individual...', 'You seem more of a... \"hands-on\" type of individual...'),
(25, 13, 1, 'N', 'N', 'I\'m sure you\'ll find better guidance on the opposite side of town. Have a nice day', 'I\'m sure you\'ll find better guidance on the opposite side of town. Have a nice day', 'I\'m sure you\'ll find better guidance on the opposite side of town. Have a nice day'),
(26, 14, 1, 'N', 'N', 'You\'ve come to the right place. But perhaps a little too soon.', 'You\'ve come to the right place. But perhaps a little too soon.', 'You\'ve come to the right place. But perhaps a little too soon.'),
(27, 14, 1, 'N', 'N', 'I have great guidance to offer you, but you need to become a little stronger first. Come back at lvl 25', 'I have great guidance to offer you, but you need to become a little stronger first. Come back at lvl 25', 'I have great guidance to offer you, but you need to become a little stronger first. Come back at lvl 25'),
(28, 15, 1, 'N', 'N', 'There are sources of power ups across the land.', 'There are sources of power ups across the land.', 'There are sources of power ups across the land.'),
(29, 15, 2, 'S', 'S', 'Here, take this demonstration! For the next 5 minutes, your animals will have 10% increased attack', 'Here, take this demonstration! For the next 5 minutes, your animals will have 10% increased attack', 'Here, take this demonstration! For the next 5 minutes, your animals will have 10% increased attack'),
(40, 30, 1, 'S', 'S', 'The snakes near here have gotten aggressive. Could you defeat a few and gather some supplies? Talk to my Assistant first, they know more.', 'I serpenti qui vicino sono diventati aggressivi. Potresti sconfiggerne alcuni e raccogliere delle forniture? Parla prima con il mio Assistente, ne sa di piu.', 'As cobras aqui perto ficaram agressivas. Podes derrotar algumas e reunir uns suprimentos? Fala primeiro com o meu Assistente, ele sabe mais.'),
(41, 31, 1, 'S', 'N', 'Watch out for the snakes near the tall grass. Bring back a couple of Potions if you find any while you are out there.', 'Attento ai serpenti vicino all\'erba alta. Porta qualche Pozione se ne trovi mentre sei la fuori.', 'Cuidado com as cobras perto da erva alta. Traz umas Pocoes se encontrares por la.'),
(42, 32, 1, 'S', 'S', 'Did you take care of the snakes and gather the supplies?', 'Ti sei occupato dei serpenti e hai raccolto le forniture?', 'Trataste das cobras e reuniste os suprimentos?'),
(43, 33, 1, 'N', 'N', 'You carry yourself like a leader. A true Trainer reads the field and raises partners???not just throws punches.', 'Ti porti come un leader. Un vero Allenatore legge il campo e fa crescere i partner, non solo colpisce.', 'Portas-te como um lider. Um verdadeiro Treinador le o campo e faz crescer parceiros???nao so golpes.'),
(44, 33, 2, 'S', 'S', 'Prove your discipline: hear my philosophy, cull five aggressive snakes, then bring earth shards, serpent DNA, and my training seal from an earth-aligned serpent. Ready to begin?', 'Dimostra disciplina: ascolta la mia filosofia, sconfiggi cinque serpenti aggressivi, poi porta frammenti di terra, DNA di serpente e il mio sigillo da un serpente di terra. Pronto a iniziare?', 'Prova disciplina: ouve a minha filosofia, derrota cinco cobras agressivas, depois traz fragmentos de terra, DNA de serpente e o meu selo de uma cobra de terra. Pronto para comecar?'),
(45, 34, 1, 'N', 'N', 'Breath first, strike second. Snakes in the high grass have grown bold???thin their numbers before they corner travelers.', 'Prima il respiro, poi il colpo. I serpenti nell\'erba alta sono diventati audaci???riduci i loro numeri prima che accerchino i viaggiatori.', 'Primeiro a respiracao, depois o golpe. As cobras na erva alta tornaram-se ousadas???reduz os numeros antes que cerquem viajantes.'),
(46, 34, 2, 'S', 'N', 'Return when five have fallen. Then we will discuss what you must gather.', 'Torna quando ne avrai abbattuti cinque. Poi parleremo di cosa devi raccogliere.', 'Volta quando cinco tiverem caido. Depois falamos do que deves reunir.'),
(47, 35, 1, 'N', 'N', 'Earth attunes the body; serpent essence attunes the bond. Hunt earth-element snakes for shards, and any serpent for DNA samples.', 'La terra armonizza il corpo; l\'essenza del serpente armonizza il legame. Caccia serpenti di terra per i frammenti, e qualsiasi serpente per i campioni di DNA.', 'A terra harmoniza o corpo; a essencia da cobra harmoniza o vinculo. Caca cobras de terra para fragmentos, e qualquer cobra para amostras de DNA.'),
(48, 35, 2, 'S', 'N', 'When you hold three earth shards and two DNA samples, seek an earth snake for my Training Seal???a token only earned during your trial.', 'Quando avrai tre frammenti di terra e due DNA, cerca un serpente di terra per il mio Sigillo???un gettone che si ottiene solo durante la prova.', 'Quando tiveres tres fragmentos de terra e dois DNA, procura uma cobra de terra para o meu Selo???um token so obtido durante a prova.'),
(49, 36, 1, 'N', 'N', 'You stand straighter. Your team feels it too. One final step remains.', 'Ti tieni piu dritto. Anche la tua squadra lo sente. Resta un ultimo passo.', 'Ficas mais ereto. A tua equipa tambem sente. Falta um ultimo passo.'),
(50, 36, 2, 'S', 'S', 'Hand over your materials and accept the Trainer\'s path. This choice is permanent.', 'Consegna i materiali e accetta la via dell\'Allenatore. Questa scelta e permanente.', 'Entrega os materiais e aceita o caminho do Treinador. Esta escolha e permanente.'),
(51, 37, 1, 'N', 'N', 'I train those who lead from the front. You seem more suited to books and formulas.', 'Alleno chi guida dal fronte. Tu sembri piu adatto a libri e formule.', 'Treino quem lidera pela frente. Pareces mais apto para livros e formulas.'),
(52, 37, 2, 'N', 'N', 'Seek the Lab Director on the other side of town. Have a good day.', 'Cerca il Direttore del Laboratorio dall\'altra parte del paese. Buona giornata.', 'Procura o Diretor do Laboratorio do outro lado da cidade. Bom dia.'),
(53, 37, 3, 'S', 'N', 'Strength without study is just noise.', 'Forza senza studio e solo rumore.', 'Forca sem estudo e so ruido.'),
(54, 38, 1, 'N', 'N', 'You seek my guidance? Train harder first.', 'Cerchi la mia guida? Allenati di piu prima.', 'Procuras a minha orientacao? Treina mais primeiro.'),
(55, 38, 2, 'S', 'N', 'Return when you reach level 25.', 'Torna quando raggiungi il livello 25.', 'Volta quando atingires o nivel 25.')
INSERT INTO `playanimaster_db`.`dialogues_options` (`id_dialog_option`, `id_dialog`, `option_n`, `option`, `option_it`, `option_pt`, `option_color`, `option_text`, `option_text_it`, `option_text_pt`) VALUES
(1, 6, 1, NULL, NULL, NULL, 'green', 'Yes, give me my first animal!', 'Si, voglio il mio primo animale!', 'Sim, quero o meu primeiro animal!'),
(2, 6, 2, NULL, NULL, NULL, 'red', 'Not now', 'Non adesso', 'Agora nao'),
