INSERT INTO `playanimaster_db`.`quests` (`id_quest`, `id_starter_npc`, `quest`, `quest_it`, `quest_pt`, `description`, `description_it`, `description_pt`, `repeatable`, `quest_type`, `lvl_min`, `lvl_max`, `ids_quests_required`) VALUES
(1, 3, 'Snake Trouble', 'Guaio di Serpenti', 'Problema com Cobras', 'The snakes near town have gotten aggressive. Help thin them out and bring back proof.', 'I serpenti vicino alla citta sono diventati aggressivi. Aiuta a contenerli e porta le prove.', 'As cobras perto da cidade ficaram agressivas. Ajuda a conte-las e traz provas.', 'N', 'hunt', 1, 100, '-1,-1'),
(2, 5, 'Become a Trainer', 'Diventa Allenatore', 'Torna-te Treinador', 'Master Ki will test your discipline: cull snakes, gather earth shards and serpent DNA, and earn his training seal from an earth-aligned serpent.', 'Master Ki mettera alla prova la tua disciplina: sconfiggi serpenti, raccogli frammenti di terra e DNA di serpente, e conquista il suo sigillo da un serpente di terra.', 'Master Ki testara a tua disciplina: derrota cobras, reune fragmentos de terra e DNA de serpente, e conquista o selo de treino de uma cobra de terra.', 'N', 'class', 25, 100, '-1,-1')
